import { describe, expect, it } from 'vitest';
import {
  worldlineFromPositions,
  worldlineToPenrose,
  stationaryWorldline,
  uniformMotionWorldline,
  circularOrbitWorldline,
} from './worldline';
import type { SpacetimeEvent } from './causal-topology';
import { LIGHT_PICOLORENZO_LY, toPicolorenzos } from './math';

// ─── Fixtures ──────────────────────────────────────────────────────

const NOW_PLO = toPicolorenzos(new Date(Date.UTC(2026, 3, 13, 0, 0, 0)));
const DURATION = 100; // picolorenzos

const origin: SpacetimeEvent = {
  id: 'origin',
  label: 'Origin',
  x: 0,
  y: 0,
  z: 0,
  pLo: NOW_PLO,
};

// ─── Tests ─────────────────────────────────────────────────────────

describe('stationaryWorldline', () => {
  it('proper time equals coordinate time for a stationary body', () => {
    const trace = stationaryWorldline(
      'rock', 'Stationary Rock', { x: 1, y: 2, z: 3 },
      NOW_PLO, NOW_PLO + DURATION, 50
    );

    expect(trace.source).toBe('GnosisWorldline');
    expect(trace.bodyId).toBe('rock');
    expect(trace.points.length).toBe(51); // 50 steps + 1

    // Proper time should equal coordinate time (no motion)
    expect(trace.totalProperTimePLo).toBeCloseTo(trace.totalCoordinateTimePLo, 6);
    expect(trace.totalCoordinateTimePLo).toBeCloseTo(DURATION, 6);
  });

  it('all positions are identical', () => {
    const trace = stationaryWorldline(
      'rock', 'Rock', { x: 5, y: 0, z: -3 },
      NOW_PLO, NOW_PLO + 10, 20
    );

    for (const pt of trace.points) {
      expect(pt.x).toBe(5);
      expect(pt.y).toBe(0);
      expect(pt.z).toBe(-3);
    }
  });
});

describe('uniformMotionWorldline', () => {
  it('positions advance linearly', () => {
    const vx = 0.001 * LIGHT_PICOLORENZO_LY; // slow speed in ly/pLo
    const trace = uniformMotionWorldline(
      'ship', 'Ship', { x: 0, y: 0, z: 0 },
      { vx, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + DURATION, 10
    );

    expect(trace.points.length).toBe(11);

    // First point at origin
    expect(trace.points[0].x).toBeCloseTo(0, 10);

    // Last point at vx * DURATION
    const lastPt = trace.points[trace.points.length - 1];
    expect(lastPt.x).toBeCloseTo(vx * DURATION, 10);
  });

  it('proper time is less than coordinate time for v > 0', () => {
    // Use a significant fraction of c (in natural units, c = LIGHT_PICOLORENZO_LY per pLo)
    const v = 0.5 * LIGHT_PICOLORENZO_LY; // 0.5c in ly/pLo
    const trace = uniformMotionWorldline(
      'fast', 'Fast Ship', { x: 0, y: 0, z: 0 },
      { vx: v, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + DURATION, 200
    );

    expect(trace.totalProperTimePLo).toBeLessThan(trace.totalCoordinateTimePLo);
    // At 0.5c, gamma = 1/sqrt(1-0.25) = 1/sqrt(0.75) ~ 1.1547
    // proper time ~ coordinate time / gamma ~ 100 * sqrt(0.75) ~ 86.6
    const expectedProper = DURATION * Math.sqrt(1 - 0.25);
    expect(trace.totalProperTimePLo).toBeCloseTo(expectedProper, 0);
  });

  it('for slow speeds, proper time is approximately coordinate time', () => {
    // v << c: 1e-6 of c
    const v = 1e-6 * LIGHT_PICOLORENZO_LY;
    const trace = uniformMotionWorldline(
      'snail', 'Snail', { x: 0, y: 0, z: 0 },
      { vx: v, vy: 0, vz: 0 },
      NOW_PLO, NOW_PLO + DURATION, 100
    );

    // Proper time should be essentially equal to coordinate time
    const ratio = trace.totalProperTimePLo / trace.totalCoordinateTimePLo;
    expect(ratio).toBeGreaterThan(0.999999);
    expect(ratio).toBeLessThanOrEqual(1.0);
  });
});

describe('circularOrbitWorldline', () => {
  it('completes one full orbit in periodPLo', () => {
    const radius = 0.01; // light-years
    const period = 50;   // picolorenzos
    const trace = circularOrbitWorldline(
      'planet', 'Planet', 0, 0, radius, period,
      NOW_PLO, NOW_PLO + period, 360
    );

    // First point: x = radius (cos(0) = 1), z = 0 (sin(0) = 0)
    expect(trace.points[0].x).toBeCloseTo(radius, 10);
    expect(trace.points[0].z).toBeCloseTo(0, 10);

    // Last point should return to start (full orbit)
    const lastPt = trace.points[trace.points.length - 1];
    expect(lastPt.x).toBeCloseTo(radius, 4);
    expect(lastPt.z).toBeCloseTo(0, 4);
  });

  it('radius stays constant within tolerance', () => {
    const centerX = 1;
    const centerZ = 2;
    const radius = 0.05;
    const period = 20;
    const trace = circularOrbitWorldline(
      'moon', 'Moon', centerX, centerZ, radius, period,
      NOW_PLO, NOW_PLO + period, 100
    );

    for (const pt of trace.points) {
      const dx = pt.x - centerX;
      const dz = pt.z - centerZ;
      const r = Math.sqrt(dx * dx + dz * dz);
      expect(r).toBeCloseTo(radius, 10);
    }
  });

  it('y coordinate is always zero (x-z ecliptic plane)', () => {
    const trace = circularOrbitWorldline(
      'sat', 'Satellite', 0, 0, 0.1, 10,
      NOW_PLO, NOW_PLO + 10, 50
    );

    for (const pt of trace.points) {
      expect(pt.y).toBe(0);
    }
  });
});

describe('worldlineFromPositions', () => {
  it('accumulates proper time correctly for known positions', () => {
    // Two stationary points separated by 10 pLo
    const positions = [
      { pLo: NOW_PLO, x: 0, y: 0, z: 0 },
      { pLo: NOW_PLO + 10, x: 0, y: 0, z: 0 },
      { pLo: NOW_PLO + 20, x: 0, y: 0, z: 0 },
    ];

    const trace = worldlineFromPositions('test', 'Test', positions);

    expect(trace.points.length).toBe(3);
    expect(trace.points[0].properTimePLo).toBe(0);
    expect(trace.points[1].properTimePLo).toBeCloseTo(10, 6);
    expect(trace.points[2].properTimePLo).toBeCloseTo(20, 6);
    expect(trace.totalProperTimePLo).toBeCloseTo(20, 6);
  });

  it('handles empty positions', () => {
    const trace = worldlineFromPositions('empty', 'Empty', []);
    expect(trace.points.length).toBe(0);
    expect(trace.totalProperTimePLo).toBe(0);
  });

  it('first point always has properTimePLo = 0', () => {
    const positions = [
      { pLo: NOW_PLO, x: 0, y: 0, z: 0 },
      { pLo: NOW_PLO + 5, x: 0.001, y: 0, z: 0 },
    ];

    const trace = worldlineFromPositions('body', 'Body', positions);
    expect(trace.points[0].properTimePLo).toBe(0);
  });
});

describe('worldlineToPenrose', () => {
  it('produces PenroseCoordinates with correct count', () => {
    const trace = stationaryWorldline(
      'rock', 'Rock', { x: 0, y: 0, z: 0 },
      NOW_PLO, NOW_PLO + 10, 5
    );

    const penrose = worldlineToPenrose(trace, origin);
    expect(penrose.bodyId).toBe('rock');
    expect(penrose.points.length).toBe(trace.points.length);
  });

  it('stationary worldline at origin has penroseSpace approximately 0', () => {
    const trace = stationaryWorldline(
      'origin-body', 'At Origin', { x: 0, y: 0, z: 0 },
      NOW_PLO, NOW_PLO + 10, 20
    );

    const penrose = worldlineToPenrose(trace, origin);

    for (const pt of penrose.points) {
      // A body at the spatial origin should have penroseSpace ~ 0
      expect(Math.abs(pt.penroseSpace)).toBeLessThan(0.01);
    }
  });
});
